import{_ as t,c as a,o,ag as r}from"./chunks/framework.9_5zbkGM.js";const n="/9eca1976d28c00ea8799c21c49ba6fb4.png",s="/8372600e445646034e28038901418990.png",l="/519c9081eae09be634220d06340de2bc.png",i="/c136287a25c98176be9f50e93451f335.png",u=JSON.parse('{"title":"接入 NewAPI","description":"","frontmatter":{},"headers":[],"relativePath":"others/new-api.md","filePath":"others/new-api.md","lastUpdated":1779596837000}'),c={name:"others/new-api.md"};function d(h,e,p,g,m,f){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="接入-newapi" tabindex="-1">接入 NewAPI <a class="header-anchor" href="#接入-newapi" aria-label="Permalink to &quot;接入 NewAPI&quot;">​</a></h1><p><a href="https://github.com/QuantumNous/new-api" target="_blank" rel="noreferrer">NewAPI</a> 是最常见的 OpenAI、Anthropic、Google等兼容的中转站。将 Tokens 作为上游渠道接入后，即可在 NewAPI 里统一调度各平台模型。下文假设你已部署 Tokens，并能在浏览器打开后台。</p><h2 id="_1-新建渠道" tabindex="-1">1. 新建渠道 <a class="header-anchor" href="#_1-新建渠道" aria-label="Permalink to &quot;1. 新建渠道&quot;">​</a></h2><p>登录 NewAPI 管理后台，进入 <strong>渠道管理</strong>，点击 <strong>添加渠道</strong>。</p><p><img src="'+n+'" alt="NewAPI 渠道管理 - 添加渠道"></p><h2 id="_2-填写基本信息" tabindex="-1">2. 填写基本信息 <a class="header-anchor" href="#_2-填写基本信息" aria-label="Permalink to &quot;2. 填写基本信息&quot;">​</a></h2><ul><li><strong>类型</strong>：可选 <code>OpenAI</code>、<code>Anthropic Claude</code>、<code>Google Gemini</code>，类型的选择要看在<strong>Tokens对应平台是否支持</strong>，具体类型选择如下表格。</li><li><strong>名称</strong>：任意便于识别的名称即可。</li><li><strong>密钥</strong>：填写 Tokens 后台的 <strong>许可证</strong>（与调用 Tokens 接口时使用的 Bearer Token 一致）。</li><li><strong>接口地址</strong>：<code>http(s)://&lt;Tokens 服务地址&gt;/&lt;平台后缀&gt;</code></li></ul><table tabindex="0"><thead><tr><th style="text-align:center;">类型</th><th style="text-align:left;">Tokens对应端点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>OpenAI</strong></td><td style="text-align:left;"><a href="/others/api-reference.html#v1chatcompletions"><code>V1ChatCompletions</code></a>、<a href="/others/api-reference.html#v1responses"><code>V1Responses</code></a>、<a href="/others/api-reference.html#v1videos"><code>V1Videos</code></a>、<a href="/others/api-reference.html#v1images"><code>V1Images</code></a></td></tr><tr><td style="text-align:center;"><strong>Anthropic Claude</strong></td><td style="text-align:left;"><a href="/others/api-reference.html#v1messages"><code>V1Messages</code></a></td></tr><tr><td style="text-align:center;"><strong>Google Gemini</strong></td><td style="text-align:left;"><a href="/others/api-reference.html#v1metamodels"><code>V1MetaModels</code></a></td></tr></tbody></table><p><img src="'+s+'" alt="NewAPI 渠道基本信息配置"></p><h2 id="_3-配置模型列表" tabindex="-1">3. 配置模型列表 <a class="header-anchor" href="#_3-配置模型列表" aria-label="Permalink to &quot;3. 配置模型列表&quot;">​</a></h2><p>先 <strong>清空</strong> 渠道里默认自带的模型，再按实际要转发的平台，填入该平台文档中列出的 <strong>模型名称</strong>。不同渠道的可用模型以对应平台页为准，例如 <a href="/platform/codex.html">Codex 终端逆向</a>、<a href="/platform/chatgpt.html">ChatGPT 官网逆向</a>。</p><p><img src="'+l+'" alt="NewAPI 渠道模型配置"></p><h2 id="_4-保存并测试" tabindex="-1">4. 保存并测试 <a class="header-anchor" href="#_4-保存并测试" aria-label="Permalink to &quot;4. 保存并测试&quot;">​</a></h2><p>保存渠道后，在 NewAPI 中对刚配置的模型做一次 <strong>渠道测试</strong>，确认能正常连通 Tokens 并返回结果。</p><p><img src="'+i+'" alt="NewAPI 渠道模型测试"></p>',15)])])}const b=t(c,[["render",d]]);export{u as __pageData,b as default};
